using UnityEngine;
using UnityEngine.UI;

namespace AegisFlowDigitalTwin.UI
{
    /// <summary>
    /// 顶部工具栏。包含放置、保存、加载、运行、停止按钮。
    /// </summary>
    public sealed class ToolbarUI : MonoBehaviour
    {
        private AegisFlow.Command.UICommandDispatcher m_Dispatcher;

        public static ToolbarUI Create(Transform parent, AegisFlow.Command.UICommandDispatcher dispatcher)
        {
            GameObject obj = new GameObject("Toolbar");
            obj.transform.SetParent(parent, false);

            RectTransform rt = obj.AddComponent<RectTransform>();
            rt.anchorMin = new Vector2(0f, 1f);
            rt.anchorMax = new Vector2(1f, 1f);
            rt.pivot = new Vector2(0.5f, 1f);
            rt.sizeDelta = new Vector2(0f, 50f);
            rt.anchoredPosition = Vector2.zero;

            HorizontalLayoutGroup layout = obj.AddComponent<HorizontalLayoutGroup>();
            layout.spacing = 8f;
            layout.padding = new RectOffset(10, 10, 5, 5);
            layout.childAlignment = TextAnchor.MiddleLeft;

            Image bg = obj.AddComponent<Image>();
            bg.color = new Color(0.1f, 0.12f, 0.16f, 0.9f);

            ToolbarUI toolbar = obj.AddComponent<ToolbarUI>();
            toolbar.m_Dispatcher = dispatcher;
            toolbar.CreateButtons();

            return toolbar;
        }

        private void CreateButtons()
        {
            CreateButton("AGV", () => SelectEntityType("AGV"), new Color(0.15f, 0.45f, 0.85f));
            CreateButton("RACK", () => SelectEntityType("RACK"), new Color(0.85f, 0.45f, 0.1f));
            CreateButton("CHARGER", () => SelectEntityType("CHARGER"), new Color(0.1f, 0.6f, 0.3f));
            CreateButton("CONVEYOR", () => SelectEntityType("CONVEYOR"), new Color(0.4f, 0.4f, 0.42f));
            CreateButton("WORKSTATION", () => SelectEntityType("WORKSTATION"), new Color(0.4f, 0.2f, 0.6f));
            CreateButton("SENSOR", () => SelectEntityType("SENSOR"), new Color(0.1f, 0.6f, 0.7f));

            CreateSpacer(20f);

            CreateButton("Save", () => m_Dispatcher.Dispatch(new AegisFlow.Command.SaveModelCommand()), new Color(0.2f, 0.5f, 0.2f));
            CreateButton("Load", () => m_Dispatcher.Dispatch(new AegisFlow.Command.LoadModelCommand("default")), new Color(0.2f, 0.4f, 0.5f));
            CreateButton("Run", () => m_Dispatcher.Dispatch(new AegisFlow.Command.StartSimulationCommand("default")), new Color(0.1f, 0.6f, 0.1f));
            CreateButton("Stop", () => m_Dispatcher.Dispatch(new AegisFlow.Command.StopSimulationCommand()), new Color(0.6f, 0.1f, 0.1f));
        }

        private void SelectEntityType(string type)
        {
            string entityId = $"{type}_{System.Guid.NewGuid():N}".Substring(0, 12);
            m_Dispatcher.Dispatch(new AegisFlow.Command.PlaceEntityCommand(
                type, entityId, type, 0f, 0f, 0f, 0f));
        }

        private void CreateButton(string label, UnityEngine.Events.UnityAction onClick, Color color)
        {
            GameObject btnObj = new GameObject($"Btn_{label}");
            btnObj.transform.SetParent(transform, false);

            Image img = btnObj.AddComponent<Image>();
            img.color = color;

            Button btn = btnObj.AddComponent<Button>();
            btn.onClick.AddListener(onClick);

            LayoutElement le = btnObj.AddComponent<LayoutElement>();
            le.preferredWidth = 90f;
            le.preferredHeight = 35f;

            GameObject txtObj = new GameObject("Text");
            txtObj.transform.SetParent(btnObj.transform, false);
            Text txt = txtObj.AddComponent<Text>();
            txt.text = label;
            txt.alignment = TextAnchor.MiddleCenter;
            txt.color = Color.white;
            txt.font = Resources.GetBuiltinResource<Font>("LegacyRuntime.ttf");
            txt.fontSize = 13;

            RectTransform txtRt = txt.GetComponent<RectTransform>();
            txtRt.anchorMin = Vector2.zero;
            txtRt.anchorMax = Vector2.one;
            txtRt.sizeDelta = Vector2.zero;
        }

        private void CreateSpacer(float width)
        {
            GameObject spacer = new GameObject("Spacer");
            spacer.transform.SetParent(transform, false);
            LayoutElement le = spacer.AddComponent<LayoutElement>();
            le.preferredWidth = width;
        }
    }
}

using AegisFlow.Bootstrap;
using UnityEngine;
using UnityEngine.AI;

namespace AegisFlowDigitalTwin.Scene
{
    /// <summary>
    /// 数字孪生场景启动器。负责初始化 AegisFlow 架构并搭建仓储环境。
    /// </summary>
    public sealed class SceneBootstrap : MonoBehaviour
    {
        [SerializeField] private bool m_BuildEnvironmentOnStart = true;

        private AppBootstrap m_AppBootstrap;

        public AegisFlowContext Context => m_AppBootstrap?.Context;

        private void Start()
        {
            m_AppBootstrap = new AppBootstrap();
            m_AppBootstrap.Initialize();

            if (m_BuildEnvironmentOnStart)
            {
                BuildEnvironment();
                SetupCamera();
                SetupLighting();
            }

            Debug.Log("[DigitalTwin] SceneBootstrap complete.");
        }

        private void Update()
        {
            m_AppBootstrap?.Update(Time.deltaTime, Time.unscaledDeltaTime);
        }

        private void OnDestroy()
        {
            m_AppBootstrap?.Shutdown();
        }

        private void BuildEnvironment()
        {
            GameObject envRoot = new GameObject("WarehouseEnvironment");
            Environment.WarehouseBuilder builder = envRoot.AddComponent<Environment.WarehouseBuilder>();
        }

        private void SetupCamera()
        {
            GameObject camObj = new GameObject("TwinCamera");
            UnityEngine.Camera cam = camObj.AddComponent<UnityEngine.Camera>();
            cam.clearFlags = CameraClearFlags.SolidColor;
            cam.backgroundColor = new Color(0.12f, 0.14f, 0.16f, 1f);
            cam.fieldOfView = 60f;
            cam.nearClipPlane = 0.1f;
            cam.farClipPlane = 500f;

            Camera.TwinOrbitCamera orbit = camObj.AddComponent<Camera.TwinOrbitCamera>();
            camObj.transform.position = new Vector3(0f, 30f, -30f);

            AudioListener listener = camObj.AddComponent<AudioListener>();
        }

        private void SetupLighting()
        {
            GameObject dirLight = new GameObject("DirectionalLight");
            Light light = dirLight.AddComponent<Light>();
            light.type = LightType.Directional;
            light.color = new Color(1f, 0.96f, 0.88f, 1f);
            light.intensity = 1.2f;
            light.shadows = LightShadows.Soft;
            dirLight.transform.rotation = Quaternion.Euler(50f, -30f, 0f);

            GameObject ambient = new GameObject("AmbientLight");
            Light ambLight = ambient.AddComponent<Light>();
            ambLight.type = LightType.Point;
            ambLight.color = new Color(0.4f, 0.5f, 0.7f, 1f);
            ambLight.intensity = 0.5f;
            ambLight.range = 60f;
            ambient.transform.position = new Vector3(0f, 20f, 0f);

            RenderSettings.ambientMode = UnityEngine.Rendering.AmbientMode.Flat;
            RenderSettings.ambientLight = new Color(0.2f, 0.22f, 0.28f, 1f);
        }
    }
}

using System.Collections.Generic;
using AegisFlow.Data;
using AegisFlow.Event;
using UnityEngine;

namespace AegisFlowDigitalTwin.UI
{
    /// <summary>
    /// UI 总根节点。管理所有面板的创建、绑定和生命周期。
    /// </summary>
    public sealed class UIRoot : MonoBehaviour
    {
        private AegisFlow.Bootstrap.AegisFlowContext m_Context;
        private DomainEventBus m_EventBus;
        private TwinDC m_TwinDC;
        private AegisFlow.Command.UICommandDispatcher m_Dispatcher;
        private EntityRepository m_EntityRepository;

        private Canvas m_Canvas;
        private ToolbarUI m_Toolbar;
        private EntityListPanel m_EntityList;
        private EntityDetailPanel m_DetailPanel;
        private RuntimeDashboardPanel m_RuntimePanel;
        private EventLogPanel m_EventLog;
        private RecoveryPanel m_RecoveryPanel;
        private ToastUI m_ToastUI;

        private readonly List<string> m_LogEntries = new List<string>();
        private const int m_MaxLogEntries = 50;

        public void Initialize(AegisFlow.Bootstrap.AegisFlowContext context)
        {
            m_Context = context;
            m_EventBus = context.DomainEventBus;
            m_TwinDC = context.TwinDC;
            m_Dispatcher = context.UICommandDispatcher;
            m_EntityRepository = context.EntityRepository;

            CreateCanvas();
            CreateToolbar();
            CreateEntityListPanel();
            CreateDetailPanel();
            CreateRuntimeDashboard();
            CreateEventLogPanel();
            CreateRecoveryPanel();
            CreateToastUI();
            BindEvents();
        }

        private void CreateCanvas()
        {
            GameObject canvasObj = new GameObject("UICanvas");
            canvasObj.transform.SetParent(transform);
            m_Canvas = canvasObj.AddComponent<Canvas>();
            m_Canvas.renderMode = RenderMode.ScreenSpaceOverlay;
            m_Canvas.sortingOrder = 10;

            canvasObj.AddComponent<UnityEngine.UI.CanvasScaler>();
            canvasObj.AddComponent<UnityEngine.UI.GraphicRaycaster>();
        }

        private void CreateToolbar()
        {
            m_Toolbar = ToolbarUI.Create(m_Canvas.transform, m_Dispatcher);
        }

        private void CreateEntityListPanel()
        {
            m_EntityList = EntityListPanel.Create(m_Canvas.transform, m_EntityRepository);
        }

        private void CreateDetailPanel()
        {
            m_DetailPanel = EntityDetailPanel.Create(m_Canvas.transform);
        }

        private void CreateRuntimeDashboard()
        {
            m_RuntimePanel = RuntimeDashboardPanel.Create(m_Canvas.transform);
        }

        private void CreateEventLogPanel()
        {
            m_EventLog = EventLogPanel.Create(m_Canvas.transform);
        }

        private void CreateRecoveryPanel()
        {
            m_RecoveryPanel = RecoveryPanel.Create(m_Canvas.transform, m_Dispatcher);
        }

        private void CreateToastUI()
        {
            m_ToastUI = ToastUI.Create(m_Canvas.transform);
        }

        private void BindEvents()
        {
            m_EventBus.Subscribe<UICommandExecutedEvent>(OnCommandExecuted);
            m_EventBus.Subscribe<EntityStatusChangedEvent>(OnEntityStatusChanged);
            m_EventBus.Subscribe<AegisFlow.Event.RuntimeStepChangedEvent>(OnRuntimeStepChanged);
            m_EventBus.Subscribe<AegisFlow.Event.ProcedureRouteFailedEvent>(OnRouteFailed);
        }

        public void Unbind()
        {
            if (m_EventBus == null)
            {
                return;
            }

            m_EventBus.Unsubscribe<UICommandExecutedEvent>(OnCommandExecuted);
            m_EventBus.Unsubscribe<EntityStatusChangedEvent>(OnEntityStatusChanged);
            m_EventBus.Unsubscribe<AegisFlow.Event.RuntimeStepChangedEvent>(OnRuntimeStepChanged);
            m_EventBus.Unsubscribe<AegisFlow.Event.ProcedureRouteFailedEvent>(OnRouteFailed);
        }

        private void OnCommandExecuted(UICommandExecutedEvent evt)
        {
            string log = $"[{evt.CreatedTime:F1}] {evt.CommandId}: {(evt.IsSuccess ? "OK" : "FAIL")} - {evt.Message}";
            m_EventLog?.AddEntry(log, evt.IsSuccess);

            if (!evt.IsSuccess)
            {
                m_ToastUI?.ShowToast(evt.Message, Color.red);
            }
            else
            {
                m_ToastUI?.ShowToast(evt.Message, Color.green);
            }

            if (evt.CommandId == "PlaceEntity" || evt.CommandId == "MoveEntity")
            {
                m_EntityList?.Refresh();
            }

            if (evt.CommandId == "StartSimulation")
            {
                m_RuntimePanel?.SetRuntimeActive(true);
            }

            if (evt.CommandId == "StopSimulation")
            {
                m_RuntimePanel?.SetRuntimeActive(false);
            }
        }

        private void OnEntityStatusChanged(EntityStatusChangedEvent evt)
        {
            string log = $"[{evt.CreatedTime:F1}] {evt.EntityId} ({evt.EntityType}) -> {evt.Status} @ ({evt.PosX:F1}, {evt.PosZ:F1})";
            m_EventLog?.AddEntry(log, true);
            m_EntityList?.Refresh();
        }

        private void OnRuntimeStepChanged(AegisFlow.Event.RuntimeStepChangedEvent evt)
        {
            m_RuntimePanel?.UpdateStep(evt.Step);
        }

        private void OnRouteFailed(AegisFlow.Event.ProcedureRouteFailedEvent evt)
        {
            m_ToastUI?.ShowToast(evt.Message, Color.red);
        }

        private void OnDestroy()
        {
            Unbind();
        }
    }
}

using UnityEngine;

namespace AegisFlowDigitalTwin.Visual
{
    /// <summary>
    /// AGV 搬运车视觉。车身 + 4 轮 + 顶部指示灯。
    /// </summary>
    public sealed class AgvVisual : EntityVisualBase
    {
        private Material m_BodyMat;
        private Material m_WheelMat;
        private Material m_LightMat;
        private GameObject m_LightObj;

        protected override void OnInitialize()
        {
            m_BodyMat = CreateMaterial(new Color(0.15f, 0.45f, 0.85f), 0.6f);
            m_WheelMat = CreateMaterial(new Color(0.08f, 0.08f, 0.08f), 0.3f);
            m_LightMat = CreateMaterial(new Color(0f, 1f, 0f), 0.9f);

            CreateChild("Body", PrimitiveType.Cube, new Vector3(0f, 0.3f, 0f), new Vector3(0.8f, 0.4f, 1.2f), m_BodyMat, transform);
            CreateChild("Top", PrimitiveType.Cube, new Vector3(0f, 0.55f, 0f), new Vector3(0.6f, 0.1f, 0.8f), m_BodyMat, transform);

            float wheelY = 0.1f;
            float wheelX = 0.45f;
            float wheelZ = 0.4f;
            CreateChild("Wheel_FL", PrimitiveType.Cylinder, new Vector3(-wheelX, wheelY, wheelZ), new Vector3(0.15f, 0.05f, 0.15f), m_WheelMat, transform);
            CreateWheelRotation(CreateChild("Wheel_FL", PrimitiveType.Cylinder, new Vector3(-wheelX, wheelY, wheelZ), new Vector3(0.15f, 0.05f, 0.15f), m_WheelMat, transform));
            CreateWheelRotation(CreateChild("Wheel_FR", PrimitiveType.Cylinder, new Vector3(wheelX, wheelY, wheelZ), new Vector3(0.15f, 0.05f, 0.15f), m_WheelMat, transform));
            CreateWheelRotation(CreateChild("Wheel_RL", PrimitiveType.Cylinder, new Vector3(-wheelX, wheelY, -wheelZ), new Vector3(0.15f, 0.05f, 0.15f), m_WheelMat, transform));
            CreateWheelRotation(CreateChild("Wheel_RR", PrimitiveType.Cylinder, new Vector3(wheelX, wheelY, -wheelZ), new Vector3(0.15f, 0.05f, 0.15f), m_WheelMat, transform));

            m_LightObj = CreateChild("StatusLight", PrimitiveType.Sphere, new Vector3(0f, 0.7f, 0f), new Vector3(0.12f, 0.12f, 0.12f), m_LightMat, transform);
        }

        private void CreateWheelRotation(GameObject wheel)
        {
            wheel.transform.Rotate(90f, 0f, 0f);
        }

        protected override void OnStatusChanged(string status)
        {
            if (m_LightObj == null)
            {
                return;
            }

            MeshRenderer renderer = m_LightObj.GetComponent<MeshRenderer>();
            if (renderer == null)
            {
                return;
            }

            Color lightColor = Color.green;
            switch (status)
            {
                case "Moving":
                    lightColor = Color.cyan;
                    break;
                case "Arrived":
                    lightColor = Color.yellow;
                    break;
                case "Charging":
                    lightColor = Color.magenta;
                    break;
                case "Error":
                case "Failed":
                    lightColor = Color.red;
                    break;
                case "Idle":
                default:
                    lightColor = Color.green;
                    break;
            }

            renderer.material.color = lightColor;
        }

        protected override void OnSelectionChanged(bool selected)
        {
            if (m_BodyMat == null)
            {
                return;
            }

            m_BodyMat.color = selected
                ? new Color(1f, 0.85f, 0.2f)
                : new Color(0.15f, 0.45f, 0.85f);
        }
    }
}

using System.Collections.Generic;
using AegisFlow.Bootstrap;
using AegisFlow.Data;
using AegisFlow.Event;
using AegisFlowDigitalTwin.Visual;
using UnityEngine;

namespace AegisFlowDigitalTwin.Simulation
{
    /// <summary>
    /// Runtime 与 Unity 视觉层的桥接器。
    /// 监听 DomainEvent，驱动 EntityVisual 和 AgvNavigator。
    /// </summary>
    public sealed class SimulationBridge : MonoBehaviour
    {
        private AegisFlowContext m_Context;
        private EntityVisualRegistry m_VisualRegistry;
        private Transform m_EntityRoot;
        private DomainEventBus m_EventBus;
        private TwinDC m_TwinDC;
        private EntityRepository m_EntityRepository;
        private bool m_IsBound;

        private readonly Dictionary<string, AgvNavigator> m_Navigators = new Dictionary<string, AgvNavigator>();
        private readonly List<string> m_PendingArrivals = new List<string>();

        public void Initialize(AegisFlowContext context, EntityVisualRegistry visualRegistry, Transform entityRoot)
        {
            m_Context = context;
            m_VisualRegistry = visualRegistry;
            m_EntityRoot = entityRoot;
            m_EventBus = context.DomainEventBus;
            m_TwinDC = context.TwinDC;
            m_EntityRepository = context.EntityRepository;
        }

        public void Bind()
        {
            if (m_IsBound || m_EventBus == null)
            {
                return;
            }

            m_EventBus.Subscribe<EntityStatusChangedEvent>(OnEntityStatusChanged);
            m_EventBus.Subscribe<SimulationEventExecutedEvent>(OnSimulationEventExecuted);
            m_IsBound = true;
        }

        public void Unbind()
        {
            if (!m_IsBound || m_EventBus == null)
            {
                return;
            }

            m_EventBus.Unsubscribe<EntityStatusChangedEvent>(OnEntityStatusChanged);
            m_EventBus.Unsubscribe<SimulationEventExecutedEvent>(OnSimulationEventExecuted);
            m_IsBound = false;
        }

        public void SyncAllVisuals()
        {
            if (m_EntityRepository == null || m_VisualRegistry == null)
            {
                return;
            }

            IReadOnlyList<EntityData> entities = m_EntityRepository.GetAll() as IReadOnlyList<EntityData>;
            if (entities == null)
            {
                foreach (EntityData entity in m_EntityRepository.GetAll())
                {
                    CreateVisualForEntity(entity);
                }
            }
            else
            {
                for (int i = 0; i < entities.Count; i++)
                {
                    CreateVisualForEntity(entities[i]);
                }
            }
        }

        public void ClearAllVisuals()
        {
            m_VisualRegistry?.Clear();
            m_Navigators.Clear();
            m_PendingArrivals.Clear();
        }

        private void CreateVisualForEntity(EntityData entity)
        {
            if (m_VisualRegistry.TryGetVisual(entity.EntityId, out _))
            {
                return;
            }

            EntityVisualBase visual = EntityVisualFactory.Create(entity.EntityId, entity.EntityType, m_EntityRoot);
            visual.SetPosition(entity.PosX, entity.PosY, entity.PosZ);
            visual.SetRotationY(entity.RotY);
            m_VisualRegistry.Register(entity.EntityId, visual);

            if (entity.EntityType == "AGV")
            {
                AgvNavigator navigator = visual.gameObject.AddComponent<AgvNavigator>();
                m_Navigators[entity.EntityId] = navigator;
            }

            m_TwinDC.UpdateTelemetry(
                entity.EntityId,
                entity.PosX, entity.PosY, entity.PosZ,
                100f, entity.Status, null, 0f);
        }

        private void OnEntityStatusChanged(EntityStatusChangedEvent evt)
        {
            if (m_VisualRegistry.TryGetVisual(evt.EntityId, out EntityVisualBase visual))
            {
                visual.SetStatus(evt.Status);
                visual.SetPosition(evt.PosX, evt.PosY, evt.PosZ);
            }
        }

        private void OnSimulationEventExecuted(SimulationEventExecutedEvent evt)
        {
            if (!evt.IsSuccess || string.IsNullOrEmpty(evt.EntityId))
            {
                return;
            }

            switch (evt.EventType)
            {
                case "Moving":
                    HandleMovingEvent(evt.EntityId);
                    break;
                case "Arrived":
                    HandleArrivedEvent(evt.EntityId);
                    break;
            }
        }

        private void HandleMovingEvent(string entityId)
        {
            if (!m_Navigators.TryGetValue(entityId, out AgvNavigator navigator))
            {
                return;
            }

            if (m_EntityRepository == null)
            {
                return;
            }

            EntityData target = FindNearestEntity(entityId, "RACK");
            if (target != null)
            {
                navigator.MoveTo(new Vector3(target.PosX, target.PosY, target.PosZ), target.EntityId);
                m_TwinDC.UpdateStatus(entityId, "Moving");
            }
        }

        private void HandleArrivedEvent(string entityId)
        {
            if (!m_Navigators.TryGetValue(entityId, out AgvNavigator navigator))
            {
                return;
            }

            navigator.Stop();
            m_TwinDC.UpdateStatus(entityId, "Arrived");
        }

        private EntityData FindNearestEntity(string sourceEntityId, string entityType)
        {
            EntityData source = m_EntityRepository.Get(sourceEntityId);
            if (source == null)
            {
                return null;
            }

            Vector3 sourcePos = new Vector3(source.PosX, source.PosY, source.PosZ);
            EntityData nearest = null;
            float nearestDist = float.MaxValue;

            foreach (EntityData entity in m_EntityRepository.GetAll())
            {
                if (entity.EntityId == sourceEntityId || entity.EntityType != entityType)
                {
                    continue;
                }

                float dist = Vector3.Distance(sourcePos, new Vector3(entity.PosX, entity.PosY, entity.PosZ));
                if (dist < nearestDist)
                {
                    nearestDist = dist;
                    nearest = entity;
                }
            }

            return nearest;
        }

        private void Update()
        {
            UpdateNavigatorArrivals();
        }

        private void UpdateNavigatorArrivals()
        {
            if (m_Navigators.Count == 0)
            {
                return;
            }

            foreach (var pair in m_Navigators)
            {
                string entityId = pair.Key;
                AgvNavigator navigator = pair.Value;

                if (navigator == null || !navigator.IsMoving)
                {
                    continue;
                }

                if (m_TwinDC.TryGetTelemetry(entityId, out EntityTelemetry telemetry))
                {
                    Vector3 pos = navigator.transform.position;
                    m_TwinDC.UpdateTelemetry(
                        entityId,
                        pos.x, pos.y, pos.z,
                        telemetry.Battery,
                        navigator.HasArrived ? "Arrived" : "Moving",
                        navigator.GetTargetEntityId(),
                        navigator.Speed);
                }

                if (navigator.HasArrived && !m_PendingArrivals.Contains(entityId))
                {
                    m_PendingArrivals.Add(entityId);
                    m_TwinDC.UpdateStatus(entityId, "Arrived");
                }
            }
        }
    }
}

using UnityEngine;

namespace AegisFlowDigitalTwin.Editor
{
    /// <summary>
    /// 编辑模式状态机。管理 Idle / Placing / Selected / Dragging 四种状态。
    /// </summary>
    public enum EditModeState
    {
        Idle,
        Placing,
        Selected,
        Dragging
    }

    /// <summary>
    /// 编辑模式总控。协调放置、选择、拖拽三种操作。
    /// </summary>
    public sealed class EditModeController : MonoBehaviour
    {
        [SerializeField] private float m_GridSize = 3f;
        [SerializeField] private LayerMask m_GroundMask = 1;
        [SerializeField] private LayerMask m_EntityMask = ~0;
        [SerializeField] private Camera m_Camera;

        private EditModeState m_State = EditModeState.Idle;
        private string m_SelectedEntityType;
        private string m_SelectedEntityId;
        private EntityPlacementController m_Placement;
        private EntitySelectionController m_Selection;
        private EntityDragController m_Drag;
        private PlacementGhostVisual m_Ghost;

        public EditModeState State => m_State;
        public string SelectedEntityId => m_SelectedEntityId;
        public string SelectedEntityType => m_SelectedEntityType;

        public event System.Action<EditModeState> OnStateChanged;
        public event System.Action<string> OnEntitySelected;
        public event System.Action<string> OnEntityDeselected;

        private void Awake()
        {
            if (m_Camera == null)
            {
                m_Camera = UnityEngine.Camera.main;
            }

            m_Ghost = gameObject.AddComponent<PlacementGhostVisual>();
            m_Placement = new EntityPlacementController(m_Camera, m_GridSize, m_GroundMask);
            m_Selection = new EntitySelectionController(m_Camera, m_EntityMask);
            m_Drag = new EntityDragController(m_Camera, m_GridSize, m_GroundMask);
        }

        public void SetPlacementType(string entityType)
        {
            m_SelectedEntityType = entityType;
            m_State = EditModeState.Placing;
            m_Ghost.Show(entityType);
            OnStateChanged?.Invoke(m_State);
        }

        public void CancelPlacement()
        {
            if (m_State == EditModeState.Placing)
            {
                m_SelectedEntityType = null;
                m_Ghost.Hide();
                m_State = EditModeState.Idle;
                OnStateChanged?.Invoke(m_State);
            }
        }

        public void Deselect()
        {
            if (m_State == EditModeState.Selected)
            {
                OnEntityDeselected?.Invoke(m_SelectedEntityId);
                m_SelectedEntityId = null;
                m_State = EditModeState.Idle;
                OnStateChanged?.Invoke(m_State);
            }
        }

        private void Update()
        {
            switch (m_State)
            {
                case EditModeState.Idle:
                    HandleIdle();
                    break;
                case EditModeState.Placing:
                    HandlePlacing();
                    break;
                case EditModeState.Selected:
                    HandleSelected();
                    break;
                case EditModeState.Dragging:
                    HandleDragging();
                    break;
            }
        }

        private void HandleIdle()
        {
            if (Input.GetMouseButtonDown(0))
            {
                string entityId = m_Selection.PickEntity(Input.mousePosition);
                if (entityId != null)
                {
                    m_SelectedEntityId = entityId;
                    m_State = EditModeState.Selected;
                    OnStateChanged?.Invoke(m_State);
                    OnEntitySelected?.Invoke(entityId);
                }
            }
        }

        private void HandlePlacing()
        {
            Vector3? pos = m_Placement.GetPlacementPosition(Input.mousePosition);
            if (pos.HasValue)
            {
                m_Ghost.UpdatePosition(pos.Value);
            }

            if (Input.GetMouseButtonDown(0) && pos.HasValue)
            {
                m_Placement.Place(m_SelectedEntityType, pos.Value);
                m_Ghost.Hide();
                m_SelectedEntityType = null;
                m_State = EditModeState.Idle;
                OnStateChanged?.Invoke(m_State);
            }

            if (Input.GetMouseButtonDown(1) || Input.GetKeyDown(KeyCode.Escape))
            {
                CancelPlacement();
            }
        }

        private void HandleSelected()
        {
            if (Input.GetMouseButtonDown(0))
            {
                string entityId = m_Selection.PickEntity(Input.mousePosition);
                if (entityId == m_SelectedEntityId)
                {
                    m_State = EditModeState.Dragging;
                    OnStateChanged?.Invoke(m_State);
                }
                else if (entityId != null)
                {
                    OnEntityDeselected?.Invoke(m_SelectedEntityId);
                    m_SelectedEntityId = entityId;
                    OnEntitySelected?.Invoke(entityId);
                }
                else
                {
                    Deselect();
                }
            }

            if (Input.GetKeyDown(KeyCode.Delete) || Input.GetKeyDown(KeyCode.Backspace))
            {
                if (m_SelectedEntityId != null)
                {
                    OnEntityDeselected?.Invoke(m_SelectedEntityId);
                    m_SelectedEntityId = null;
                    m_State = EditModeState.Idle;
                    OnStateChanged?.Invoke(m_State);
                }
            }
        }

        private void HandleDragging()
        {
            Vector3? pos = m_Drag.GetDragPosition(Input.mousePosition);
            if (pos.HasValue && m_SelectedEntityId != null)
            {
                m_Drag.Move(m_SelectedEntityId, pos.Value);
            }

            if (Input.GetMouseButtonUp(0))
            {
                m_State = EditModeState.Selected;
                OnStateChanged?.Invoke(m_State);
            }
        }
    }
}

using AegisFlow.Bootstrap;
using AegisFlowDigitalTwin.UI;
using AegisFlowDigitalTwin.Visual;
using UnityEngine;

namespace AegisFlowDigitalTwin.Scene
{
    /// <summary>
    /// 一键启动入口。在场景中放置此 MonoBehaviour 即可启动整个数字孪生系统。
    /// </summary>
    public sealed class DigitalTwinEntrance : MonoBehaviour
    {
        private SceneBootstrap m_SceneBootstrap;
        private UIRoot m_UIRoot;
        private SimulationBridge m_SimBridge;
        private EntityVisualRegistry m_VisualRegistry;
        private Transform m_EntityRoot;
        private AegisFlowContext m_Context;

        private void Start()
        {
            m_SceneBootstrap = gameObject.GetComponent<SceneBootstrap>();
            if (m_SceneBootstrap == null)
            {
                m_SceneBootstrap = gameObject.AddComponent<SceneBootstrap>();
            }

            m_EntityRoot = new GameObject("EntityRoot").transform;

            m_VisualRegistry = new EntityVisualRegistry(m_EntityRoot);

            GameObject bridgeObj = new GameObject("SimulationBridge");
            m_SimBridge = bridgeObj.AddComponent<SimulationBridge>();

            GameObject uiObj = new GameObject("UIRoot");
            m_UIRoot = uiObj.AddComponent<UIRoot>();

            Invoke(nameof(LateInitialize), 0.1f);
        }

        private void LateInitialize()
        {
            m_Context = m_SceneBootstrap?.Context;
            if (m_Context == null)
            {
                Debug.LogError("[DigitalTwin] AegisFlowContext not available.");
                return;
            }

            m_SimBridge.Initialize(m_Context, m_VisualRegistry, m_EntityRoot);
            m_SimBridge.Bind();
            m_SimBridge.SyncAllVisuals();

            m_UIRoot.Initialize(m_Context);

            Debug.Log("[DigitalTwin] Full system initialized.");
        }

        private void OnDestroy()
        {
            m_SimBridge?.Unbind();
            m_UIRoot?.Unbind();
            m_VisualRegistry?.Clear();
        }
    }
}

using AegisFlow.Procedure;
using AegisFlow.Resource;
using AegisFlow.Save;
using UnityEngine;
using UnityGameFramework.Runtime;

namespace AegisFlow.Bootstrap
{
    /// <summary>
    /// 玄盾流架构启动器。负责注册基础设施与启动首个 Procedure。
    /// </summary>
    public sealed class AppBootstrap
    {
        private ProcedureController m_ProcedureController;
        private ProcedureDependencies m_ProcedureDependencies;
        private AegisFlowContext m_Context;

        public AegisFlowContext Context => m_Context;

        public void Initialize()
        {
            Debug.Log("[AegisFlow] AppBootstrap Initialize.");

            ResourceComponent resourceComponent = UnityGameFramework.Runtime.GameEntry.GetComponent<ResourceComponent>();
            AssetService.Initialize(resourceComponent != null
                ? (IAssetLoader)new UGFResourceAdapter(resourceComponent)
                : new ResourcesLegacyAdapter());
            SaveAppService.Initialize(new LocalSaveRepository());

            m_Context = new AegisFlowContext();
            m_Context.Build();

            m_ProcedureController = new ProcedureController();
            m_ProcedureDependencies = new ProcedureDependencies(
                m_Context.SimulationDC,
                m_Context.TwinDC,
                m_Context.PlayerDomainService,
                m_Context.TwinDomainService,
                m_Context.ModelDomainService,
                m_Context.SimulationAppService,
                m_Context.SimulationModelAppService,
                m_Context.SimulationRuntimeController,
                m_Context.DomainEventBus);
            m_ProcedureController.ChangeProcedure(new ProcedureLaunch(m_ProcedureController, m_ProcedureDependencies));
        }

        public void Update(float elapseSeconds, float realElapseSeconds)
        {
            m_ProcedureController?.Update(elapseSeconds, realElapseSeconds);
        }

        public void Shutdown()
        {
            m_ProcedureController?.Shutdown();
            m_ProcedureDependencies = null;
            m_Context?.Dispose();
            m_Context = null;

            SaveAppService.Shutdown();
            AssetService.Shutdown();

            Debug.Log("[AegisFlow] AppBootstrap Shutdown.");
        }
    }
}

