        private Vector3 SnapToGrid(Vector3 pos)
        {
            float x = Mathf.Round(pos.x / m_GridSize) * m_GridSize;
            float z = Mathf.Round(pos.z / m_GridSize) * m_GridSize;
            return new Vector3(x, 0f, z);
        }
    }
}

