    public sealed class WarehouseBuilder : MonoBehaviour
    {
        [SerializeField] private float m_FloorSize = 60f;
        [SerializeField] private float m_WallHeight = 4f;
        [SerializeField] private float m_GridSpacing = 3f;

        private void Start()
        {
            BuildFloor();
            BuildWalls();
            BuildGridMarkers();
